int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<int> c(n - 1), s(n - 1), f(n - 1);
    for (int i = 0; i < n - 1; ++i) cin >> c[i] >> s[i] >> f[i];

    for (int start = 0; start < n; ++start) {
        int time = 0;
        for (int i = start; i < n - 1; ++i) {
            if (time < s[i]) time = s[i];
            else if (time % f[i] != 0) time += f[i] - time % f[i];
            time += c[i];
        }
        cout << time << '\n';
    }
    return 0;
}

