int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    const int MAXV = 100000;
    vector<int> prime(MAXV + 1, 1);
    prime[0] = prime[1] = 0;
    for (int i = 2; i * i <= MAXV; ++i) {
        if (!prime[i]) continue;
        for (int j = i * i; j <= MAXV; j += i) prime[j] = 0;
    }
    vector<int> pref(MAXV + 1, 0);
    for (int x = 1; x <= MAXV; ++x) {
        pref[x] = pref[x - 1];
        if (x % 2 == 1 && prime[x] && prime[(x + 1) / 2]) ++pref[x];
    }

    int q;
    cin >> q;
    while (q--) {
        int l, r;
        cin >> l >> r;
        cout << pref[r] - pref[l - 1] << '\n';
    }
    return 0;
}

