    int n, m;
    cin >> n >> m;
    vector<int> x(m);
    for (int& v : x) cin >> v;
    if (n >= m) {
        cout << 0 << '\n';
        return 0;
    }
    sort(x.begin(), x.end());
    vector<int> gap;
    int total = x.back() - x.front();
    for (int i = 0; i + 1 < m; ++i) gap.push_back(x[i + 1] - x[i]);
    sort(gap.rbegin(), gap.rend());
    for (int i = 0; i < n - 1; ++i) total -= gap[i];
    cout << total << '\n';
    return 0;
}

