#include <algorithm>
#include <cmath>
#include <iostream>
#include <map>
#include <numeric>
#include <set>
#include <string>
#include <tuple>
#include <utility>
#include <vector>
using namespace std;

int n, A, B, C;
vector<int> l;
const int INF = 1 << 28;

int dfs(int idx, int a, int b, int c, int ca, int cb, int cc) {
    if (idx == n) {
        if (ca == 0 || cb == 0 || cc == 0) return INF;
        int cost = abs(a - A) + abs(b - B) + abs(c - C);
        cost += 10 * ((ca - 1) + (cb - 1) + (cc - 1));
        return cost;
    }
    int res = dfs(idx + 1, a, b, c, ca, cb, cc); // 不使用
    res = min(res, dfs(idx + 1, a + l[idx], b, c, ca + 1, cb, cc));
    res = min(res, dfs(idx + 1, a, b + l[idx], c, ca, cb + 1, cc));
    res = min(res, dfs(idx + 1, a, b, c + l[idx], ca, cb, cc + 1));
    return res;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    cin >> n >> A >> B >> C;
    l.resize(n);
    for (int& x : l) cin >> x;
    cout << dfs(0, 0, 0, 0, 0, 0, 0) << '\n';
    return 0;
}

