#include <algorithm>
#include <cmath>
#include <iostream>
#include <map>
#include <numeric>
#include <set>
#include <string>
#include <tuple>
#include <utility>
#include <vector>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    long long m;
    cin >> n >> m;
    vector<pair<long long, long long>> shops(n);
    for (auto& shop : shops) cin >> shop.first >> shop.second;
    sort(shops.begin(), shops.end());
    long long ans = 0;
    for (const auto& shop : shops) {
        long long buy = min(m, shop.second);
        ans += buy * shop.first;
        m -= buy;
        if (m == 0) break;
    }
    cout << ans << '\n';
    return 0;
}
